namespace CourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Course
{
    public string Id { get; set; } = "";
    public string Title { get; set; } = "";
    public string DepartmentId { get; set; } = "";
    public string DepartmentName { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public string CourseId { get; set; } = "";
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "math", Name = "Mathematics", Description = "Pure and applied mathematics covering algebra, calculus, and statistics." },
        new() { Id = "eng", Name = "English", Description = "Literature, creative writing, and composition studies." },
        new() { Id = "phys", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "hist", Name = "History", Description = "Examination of past events, societies, and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = "CS101", Title = "Introduction to Programming", DepartmentId = "cs", DepartmentName = "Computer Science", Description = "Learn the fundamentals of programming using C#. Covers variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming pedagogy.", IsFeatured = true },
        new() { Id = "CS201", Title = "Data Structures & Algorithms", DepartmentId = "cs", DepartmentName = "Computer Science", Description = "Study of fundamental data structures (arrays, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has contributed to several open-source projects.", IsFeatured = true },
        new() { Id = "CS301", Title = "Database Systems", DepartmentId = "cs", DepartmentName = "Computer Science", Description = "Relational database design, SQL, normalization, and introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Rodriguez", InstructorBio = "Prof. Rodriguez worked as a database architect at major tech companies for a decade before joining academia.", IsFeatured = false },
        new() { Id = "MATH101", Title = "Calculus I", DepartmentId = "math", DepartmentName = "Mathematics", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is a renowned mathematician with research interests in differential equations.", IsFeatured = true },
        new() { Id = "MATH201", Title = "Linear Algebra", DepartmentId = "math", DepartmentName = "Mathematics", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on computational linear algebra and numerical methods.", IsFeatured = false },
        new() { Id = "MATH301", Title = "Probability & Statistics", DepartmentId = "math", DepartmentName = "Mathematics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is a renowned mathematician with research interests in differential equations.", IsFeatured = false },
        new() { Id = "ENG101", Title = "College Composition", DepartmentId = "eng", DepartmentName = "English", Description = "Develop effective academic writing skills through essay composition and critical reading.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Prof. Diana Hughes", InstructorBio = "Prof. Hughes is a published author and writing workshop leader with expertise in rhetoric.", IsFeatured = false },
        new() { Id = "ENG201", Title = "American Literature", DepartmentId = "eng", DepartmentName = "English", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim has authored three books on 20th-century American fiction.", IsFeatured = true },
        new() { Id = "PHYS101", Title = "General Physics I", DepartmentId = "phys", DepartmentName = "Physics", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:00 PM", InstructorName = "Dr. Lisa Nakamura", InstructorBio = "Dr. Nakamura is an experimental physicist specializing in condensed matter research.", IsFeatured = false },
        new() { Id = "PHYS201", Title = "Electromagnetism", DepartmentId = "phys", DepartmentName = "Physics", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM + Fri Lab 1:00–3:00 PM", InstructorName = "Dr. Michael Grant", InstructorBio = "Dr. Grant's research focuses on quantum electrodynamics and photonics.", IsFeatured = false },
        new() { Id = "HIST101", Title = "World History to 1500", DepartmentId = "hist", DepartmentName = "History", Description = "Survey of world civilizations from ancient times through the late medieval period.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Patricia Okafor", InstructorBio = "Dr. Okafor is a specialist in ancient Mediterranean and West African history.", IsFeatured = false },
        new() { Id = "HIST201", Title = "Modern European History", DepartmentId = "hist", DepartmentName = "History", Description = "European history from the Renaissance through the 21st century.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", InstructorName = "Dr. Heinrich Müller", InstructorBio = "Dr. Müller has published on the political history of modern Europe and transatlantic relations.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, string? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
            query = query.Where(c => c.DepartmentId == departmentId);

        if (!string.IsNullOrWhiteSpace(searchTerm))
            query = query.Where(c =>
                c.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                c.Id.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollment(EnrollmentRequest request) =>
        GetCourse(request.CourseId) is not null;
}

