@page "/courses"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4" data-enhance>
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, course ID, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="department" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(dept.Id == Department)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Course ID</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in _courses)
            {
                <tr>
                    <td>@course.Id</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "department")]
    public string? Department { get; set; }

    private List<Course> _courses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Search, Department);
    }
}

@page "/courses/{CourseId}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

@if (_course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The course you're looking for does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <PageTitle>@_course.Id – @_course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?department=@_course.DepartmentId">@_course.DepartmentName</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Id</li>
        </ol>
    </nav>

    <h1>@_course.Id – @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@_course.Description</p>

            <h2 class="mt-4">Schedule</h2>
            <p><strong>@_course.Schedule</strong></p>

            <h2 class="mt-4">Credits</h2>
            <p><span class="badge bg-primary fs-6">@_course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Instructor</h5>
                </div>
                <div class="card-body">
                    <h6>@_course.InstructorName</h6>
                    <p class="text-muted">@_course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?course=@_course.Id" class="btn btn-success w-100">Request Enrollment</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string CourseId { get; set; } = "";

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = Catalog.GetCourse(CourseId);
    }
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Your enrollment request for <strong>@_selectedCourseName</strong> has been submitted successfully. You will receive confirmation via your student email.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <form method="post" class="col-md-8" @formname="enrollment" data-enhance>
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id" selected="@(course.Id == Model.CourseId)">@course.Id – @course.Title (@course.Credits cr)</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "course")]
    public string? PreselectedCourse { get; set; }

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseName = "";

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (!string.IsNullOrEmpty(PreselectedCourse) && string.IsNullOrEmpty(Model.CourseId))
        {
            Model.CourseId = PreselectedCourse;
        }

        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? ""))
        {
            if (!string.IsNullOrEmpty(Model.StudentName) &&
                !string.IsNullOrEmpty(Model.StudentId) &&
                !string.IsNullOrEmpty(Model.CourseId))
            {
                _submitted = Catalog.SubmitEnrollment(Model);
                _selectedCourseName = Catalog.GetCourse(Model.CourseId)?.Title ?? Model.CourseId;
            }
        }
    }

    [CascadingParameter]
    public HttpContext? HttpContextAccessor { get; set; }
}

