@page "/"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome! Browse our departments and courses, or submit an enrollment request.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Id – @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@course.Description[..Math.Min(100, course.Description.Length)]…</p>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group">
    @foreach (var dept in _departments)
    {
        <a href="courses?department=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Name</strong> — @dept.Description
        </a>
    }
</div>

@code {
    private List<Course> _featuredCourses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featuredCourses = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetDepartments();
    }
}

